// API utilities for TypeArena
import { mockUsers, mockTournaments, mockLeaderboard, mockRaceResults } from './mockData';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:3001/api';
const ADMIN_TOKEN_KEY = 'typearena_admin_token';
const LOCAL_USERS_KEY = 'typearena_local_users';
const DEFAULT_ADMIN_EMAIL = 'caleb@gmail.com';
const DEFAULT_ADMIN_PASSWORD = 'Caleb123';

const hashPassword = async (password) => {
  const value = String(password ?? '');
  const cryptoApi = typeof window !== 'undefined' ? window.crypto : null;

  if (cryptoApi?.subtle) {
    const data = new TextEncoder().encode(value);
    const digest = await cryptoApi.subtle.digest('SHA-256', data);
    return Array.from(new Uint8Array(digest))
      .map((byte) => byte.toString(16).padStart(2, '0'))
      .join('');
  }

  return value;
};

const getStoredUser = () => {
  const raw = localStorage.getItem('typearena_user');
  return raw ? JSON.parse(raw) : null;
};

const sanitizeUser = (user) => {
  if (!user) return user;
  const { passwordHash, ...safeUser } = user;
  return safeUser;
};

const setStoredUser = (user) => {
  localStorage.setItem('typearena_user', JSON.stringify(sanitizeUser(user)));
};

const buildHeaders = (extraHeaders = {}) => {
  const headers = {
    'Content-Type': 'application/json',
    ...extraHeaders,
  };

  const user = getStoredUser();
  if (user?.id) {
    headers['X-User-Id'] = String(user.id);
  }

  return headers;
};

const parseResponse = async (response) => {
  const data = await response.json().catch(() => ({}));
  if (!response.ok) {
    const message = data?.message || 'Request failed';
    throw new Error(message);
  }
  return data;
};

const shouldUseLocalFallback = (error) => {
  const msg = String(error?.message || '').toLowerCase();
  return msg.includes('failed to fetch') || msg.includes('networkerror') || msg.includes('load failed');
};

const getLocalUsers = () => {
  const localRaw = localStorage.getItem(LOCAL_USERS_KEY);
  const localUsers = localRaw ? JSON.parse(localRaw) : [];
  return [...mockUsers, ...localUsers];
};

const saveLocalUsers = (users) => {
  localStorage.setItem(LOCAL_USERS_KEY, JSON.stringify(users));
};

// User APIs
export const fetchCurrentUser = async () => {
  try {
    const stored = getStoredUser();
    if (!stored?.id) return null;

    const response = await fetch(`${API_BASE_URL}/user/me`, {
      headers: buildHeaders(),
    });
    const user = await parseResponse(response);
    setStoredUser(user);
    return user;
  } catch (error) {
    console.error('Error fetching user:', error);
    return getStoredUser();
  }
};

export const loginUser = async (email, password) => {
  try {
    const response = await fetch(`${API_BASE_URL}/auth/login`, {
      method: 'POST',
      headers: buildHeaders(),
      body: JSON.stringify({ email, password }),
    });
    const user = await parseResponse(response);
    setStoredUser(user);
    return user;
  } catch (error) {
    console.error('Login error:', error);
    if (shouldUseLocalFallback(error)) {
      const passwordHash = await hashPassword(password);
      const match = getLocalUsers().find((u) => u.email.toLowerCase() === String(email).toLowerCase());
      if (!match) {
        throw new Error('No account found with that email in offline mode. Please sign up first.');
      }
      if ((match.passwordHash || '') !== passwordHash) {
        throw new Error('Invalid email or password.');
      }
      const safeUser = sanitizeUser(match);
      setStoredUser(safeUser);
      return safeUser;
    }
    throw error;
  }
};

export const signupUser = async (username, email, password, phoneNumber) => {
  try {
    const response = await fetch(`${API_BASE_URL}/auth/signup`, {
      method: 'POST',
      headers: buildHeaders(),
      body: JSON.stringify({ username, email, password, phoneNumber }),
    });
    const user = await parseResponse(response);
    setStoredUser(user);
    return user;
  } catch (error) {
    console.error('Signup error:', error);
    if (shouldUseLocalFallback(error)) {
      const existing = getLocalUsers().find((u) => u.email.toLowerCase() === String(email).toLowerCase());
      if (existing) {
        throw new Error('An account with this email already exists.');
      }

      const localRaw = localStorage.getItem(LOCAL_USERS_KEY);
      const localUsers = localRaw ? JSON.parse(localRaw) : [];
      const passwordHash = await hashPassword(password);
      const newUser = {
        id: Date.now(),
        username,
        email,
        passwordHash,
        phoneNumber,
        wpm: 0,
        accuracy: 0,
        totalRaces: 0,
        wins: 0,
        balance: 0,
      };
      localUsers.push(newUser);
      saveLocalUsers(localUsers);
      const safeUser = sanitizeUser(newUser);
      setStoredUser(safeUser);
      return safeUser;
    }
    throw error;
  }
};

// Tournament APIs
export const fetchTournaments = async () => {
  try {
    const response = await fetch(`${API_BASE_URL}/tournaments`, {
      headers: buildHeaders(),
    });
    return await parseResponse(response);
  } catch (error) {
    console.error('Error fetching tournaments:', error);
    return mockTournaments.map((t) => ({ ...t }));
  }
};

export const joinTournament = async (tournamentId) => {
  try {
    const response = await fetch(`${API_BASE_URL}/tournaments/${tournamentId}/join`, {
      method: 'POST',
      headers: buildHeaders(),
    });
    const result = await parseResponse(response);

    if (result?.user) {
      setStoredUser(result.user);
    }

    return result;
  } catch (error) {
    console.error('Error joining tournament:', error);
    throw error;
  }
};

// Leaderboard APIs
export const fetchLeaderboard = async (limit = 100) => {
  try {
    const response = await fetch(`${API_BASE_URL}/leaderboard?limit=${limit}`, {
      headers: buildHeaders(),
    });
    return await parseResponse(response);
  } catch (error) {
    console.error('Error fetching leaderboard:', error);
    return mockLeaderboard;
  }
};

// Race/Results APIs
export const submitRaceResult = async (raceData) => {
  try {
    const response = await fetch(`${API_BASE_URL}/races/submit`, {
      method: 'POST',
      headers: buildHeaders(),
      body: JSON.stringify(raceData),
    });
    const result = await parseResponse(response);

    // Refresh local user snapshot after race updates
    const refreshedUser = await fetchCurrentUser();
    if (refreshedUser) {
      setStoredUser(refreshedUser);
    }

    return result;
  } catch (error) {
    console.error('Error submitting race result:', error);
    throw error;
  }
};

export const fetchRaceHistory = async (userId) => {
  try {
    const response = await fetch(`${API_BASE_URL}/users/${userId}/races`, {
      headers: buildHeaders(),
    });
    return await parseResponse(response);
  } catch (error) {
    console.error('Error fetching race history:', error);
    return mockRaceResults;
  }
};

// User Profile APIs
export const fetchUserStats = async (userId) => {
  try {
    const response = await fetch(`${API_BASE_URL}/user/me`, {
      headers: buildHeaders(),
    });
    return await parseResponse(response);
  } catch (error) {
    console.error('Error fetching user stats:', error);
    return mockUsers.find((u) => u.id === userId) || mockUsers[0] || null;
  }
};

export const updateUserProfile = async (userId, updates) => {
  try {
    const response = await fetch(`${API_BASE_URL}/users/${userId}`, {
      method: 'PUT',
      headers: buildHeaders(),
      body: JSON.stringify(updates),
    });
    const user = await parseResponse(response);
    setStoredUser(user);
    return user;
  } catch (error) {
    console.error('Error updating profile:', error);
    throw error;
  }
};

export const addFundsToWallet = async (amount, phoneNumber) => {
  try {
    const response = await fetch(`${API_BASE_URL}/wallet/topup`, {
      method: 'POST',
      headers: buildHeaders(),
      body: JSON.stringify({ amount: Number(amount), phoneNumber }),
    });
    const data = await parseResponse(response);
    if (data?.user) {
      setStoredUser(data.user);
    }
    return data;
  } catch (error) {
    console.error('Error adding funds:', error);
    throw error;
  }
};

export const sendPrizeToWinner = async ({ userId, amount, tournamentId = null }) => {
  try {
    const response = await fetch(`${API_BASE_URL}/prizes/payout`, {
      method: 'POST',
      headers: buildHeaders(),
      body: JSON.stringify({ userId, amount, tournamentId }),
    });
    return await parseResponse(response);
  } catch (error) {
    console.error('Error sending prize payout:', error);
    throw error;
  }
};

export const adminLogin = async (email, password) => {
  try {
    const response = await fetch(`${API_BASE_URL}/admin/login`, {
      method: 'POST',
      headers: buildHeaders(),
      body: JSON.stringify({ email, password }),
    });
    const data = await parseResponse(response);
    if (data?.token) {
      localStorage.setItem(ADMIN_TOKEN_KEY, data.token);
    }
    return data;
  } catch (error) {
    console.error('Admin login error:', error);
    if (shouldUseLocalFallback(error)) {
      const normalizedEmail = String(email || '').trim().toLowerCase();
      const normalizedPassword = String(password || '').trim();
      if (
        normalizedEmail === DEFAULT_ADMIN_EMAIL.toLowerCase() &&
        normalizedPassword === DEFAULT_ADMIN_PASSWORD
      ) {
        const offlineToken = `offline_admin_${Date.now()}`;
        localStorage.setItem(ADMIN_TOKEN_KEY, offlineToken);
        return { token: offlineToken, adminEmail: DEFAULT_ADMIN_EMAIL, mode: 'offline' };
      }
      throw new Error('Invalid admin credentials.');
    }
    throw error;
  }
};

export const adminLogout = () => {
  localStorage.removeItem(ADMIN_TOKEN_KEY);
};

export const getAdminToken = () => localStorage.getItem(ADMIN_TOKEN_KEY);

export const adminCreateTournament = async (payload) => {
  const token = getAdminToken();
  if (!token) {
    throw new Error('Admin session not found. Please login again.');
  }

  try {
    const response = await fetch(`${API_BASE_URL}/admin/tournaments`, {
      method: 'POST',
      headers: {
        ...buildHeaders(),
        'X-Admin-Token': token,
      },
      body: JSON.stringify(payload),
    });
    return await parseResponse(response);
  } catch (error) {
    console.error('Admin create tournament error:', error);
    throw error;
  }
};
